local statusLabel = FarmRight:AddLabel({ Text = "Statut : Inactif " })
local worldLabel  = FarmRight:AddLabel({ Text = "Tour : détection... " })

task.spawn(function()
    while not Library.Unloaded do
        task.wait(0.5)
        if M.isSharedStallActive() then
            local remaining = math.max(0, math.ceil(M.getSharedStallUntil() - tick()))
            statusLabel:SetText("Status: Stalled " .. remaining .. "s ")
        elseif M.isClaimingWins() then
            statusLabel:SetText("Statut : Récupération des victoires ")
        elseif M.isListening() then
            statusLabel:SetText("Statut : En écoute... ")
        elseif M.isAllCaptured() then
            statusLabel:SetText("Statut : Prêt ! ")
        else
            statusLabel:SetText("Statut : Pas encore configuré")
        end
        worldLabel:SetText("Tower: " .. (M.getCurrentWorldName() or "not found") .. " ")
    end
end)

