-- FARM POSITION TAB
local SpotLeft  = Tabs.Spot:AddLeftGroupbox("Remplacement de position ")
local SpotRight = Tabs.Spot:AddRightGroupbox("Touche de sauvegarde rapide ")

local overrideLabel = SpotLeft:AddLabel({ Text = "Position personnalisée : DÉSACTIVÉE " })
local savedCFLabel  = SpotLeft:AddLabel({ Text = "Enregistré : aucun " })

SpotLeft:AddButton("Enregistrer la position actuelle ", function()
    local char = game.Players.LocalPlayer.Character
    if not char then Library:Notify({Title="Erreur ", Description="Aucun personnage ! ", Duration=3}) return end
    local root = char:FindFirstChild("HumanoidRootPart")
    if not root then Library:Notify({Title="Erreur ", Description="Aucun HumanoidRootPart ! ", Duration=3}) return end
    M.setCustomCFrameOverride(root.CFrame)
    local p = root.Position
    savedCFLabel:SetText(string.format("Saved: %.1f, %.1f, %.1f ", p.X, p.Y, p.Z))
    Library:Notify({Title="Position enregistrée ! ", Description=string.format("%.1f, %.1f, %.1f", p.X, p.Y, p.Z), Duration=4})
end)

SpotLeft:AddButton("Effacer la position personnalisée", function()
    M.setCustomCFrameOverride(nil)
    savedCFLabel:SetText("Enregistré : aucun ")
    Library:Notify({Title="Effacé ", Description="Utilisation de l'emplacement capturé d'origine. ", Duration=3})
end)

task.spawn(function()
    while not Library.Unloaded do
        task.wait(0.5)
        overrideLabel:SetText("Custom Position: " .. (M.getCustomCFrameOverride() and "ON " or "OFF "))
    end
end)

local keybindLabel = SpotRight:AddLabel({ Text = "Touche de sauvegarde rapide : F " })

SpotRight:AddButton("Définir la touche de sauvegarde rapide ", function()
