end)

SpotRight:AddButton("Effacer la touche de sauvegarde rapide ", function()
    M.setTeleportKeybind(nil)
    keybindLabel:SetText("Touche de sauvegarde rapide : aucune ")
    Library:Notify({Title="Touche effacée ", Description="Aucune touche de sauvegarde rapide définie. ", Duration=3})
end)

M.onKeybindSet = function(keyCode)
    keybindLabel:SetText("Quick-Save Key: " .. keyCode.Name .. " ")
end

M.onSpotSaved = function(p)
    savedCFLabel:SetText(string.format("Saved: %.1f, %.1f, %.1f ", p.X, p.Y, p.Z))
end

